// 1. 使用 let 声明变量
let userName = '张三';
let age = 20;

// 修改变量的值
age = 21; // 正常工作

// 2. 使用 const 声明常量
const PI = 3.14159;
const BIRTH_YEAR = 2005;

// 尝试修改常量会报错！
// PI = 3.14; // TypeError: Assignment to constant variable.

// 3. 变量命名规范（驼峰命名法）
let myStudentId = '2026001';
let isLogin = true;

// 算术运算符：+ - * / % (取余)
let a = 10 % 3; // a 的值是 1 (10除以3的余数)

// 字符串拼接：+ 可以连接字符串
let greeting = "Hello " + "World"; // "Hello World"
let msg = "Score: " + 100; // "Score: 100" (数字自动转为字符串)

// 比较运算符：> < >= <= == === !==
let x = 5;
console.log(x > 3);  // true
console.log(x == "5");  // true (双等号只比值，不比类型)
console.log(x === "5"); // false (三等号严格比较：值和类型必须都一样！)

// 逻辑运算符：&& (与)  || (或)  ! (非)
let isAdult = true;
let hasTicket = false;
console.log(isAdult && hasTicket); // false (两个都必须为true)
console.log(isAdult || hasTicket); // true (只要有一个为true)
console.log(!isAdult);             // false (取反)

let score = 85;

// 单分支 / 双分支 / 多分支
if (score >= 90) {
  console.log("优秀");
} else if (score >= 80) {
  console.log("良好"); // 85会命中这一条
} else if (score >= 60) {
  console.log("及格");
} else {
  console.log("不及格");
}

// Switch 语句（适合大量特定值的匹配）
let day = 3;
switch (day) {
  case 1:
    console.log("星期一");
    break;
  case 2:
    console.log("星期二");
    break;
  case 3:
    console.log("星期三"); // 输出此行
    break;
  default:
    console.log("未知日期");
}

// 1. for 循环
// 语法：for(初始化; 循环条件; 迭代操作)
for (let i = 1; i <= 5; i++) {
  console.log("第 " + i + " 次打印");
}

// 遍历数组是 for 循环最常见的用途
let fruits = ["苹果", "香蕉", "橘子"];
for (let i = 0; i < fruits.length; i++) {
  console.log("我喜欢吃：" + fruits[i]);
}

// 2. while 循环 (不知道具体循环次数，只知道结束条件时使用)
let hp = 10;
while (hp > 0) {
  console.log("被攻击！当前血量：" + hp);
  hp -= 3; // 每次减3血 (等同于 hp = hp - 3)
}
console.log("游戏结束");

// 1. 定义函数 (声明式)
function greet(name) {
  let msg = "Hello, " + name + "!";
  return msg; // 将结果返回给调用者
}

// 调用函数
let result1 = greet("张三");
console.log(result1); // 输出: Hello, 张三!
console.log(greet("李四")); // 输出: Hello, 李四!

// 2. 现代写法：箭头函数 (Arrow Function) ES6引入
const add = (a, b) => {
  return a + b;
};

console.log(add(10, 5)); // 输出: 15

// 如果箭头函数只有一行代码，可以进一步简写（省略{}和return）：
const multiply = (x, y) => x * y;
console.log(multiply(4, 5)); // 输出: 20

// --- String --- 
let text = "HTML,CSS,JS";
console.log(text.length); // 11
let arr = text.split(","); //["HTML", "CSS", "JS"]

// --- Array ---
arr.push("Vue"); // 数组末尾添加元素：["HTML", "CSS", "JS", "Vue"]
console.log(arr.join(" -> ")); // "HTML -> CSS -> JS -> Vue"

// --- Math ---
let rand = Math.random(); // 生成 0 到 1 之间的随机小数
// 生成 1 到 10 的随机整数公式：
let dice = Math.floor(Math.random() * 10) + 1;
console.log("掷骰子：" + dice);

// --- Date ---
let now = new Date();
let year = now.getFullYear();
let month = now.getMonth() + 1; // ⚠️ 注意：月份是从 0 开始的！(0代表1月)
let date = now.getDate();
console.log(`今天是：${year}年${month}月${date}日`);

// 1. 弹窗系列 (都属于 window 对象，通常省略 window.)
alert("这是一个普通的提示框");

let result = confirm("确认要删除这条数据吗？"); 
// 确认框，用户点确定返回true，点取消返回false
if (result) {
  console.log("执行删除...");
}

// 2. 页面跳转与刷新 (location 对象)
console.log("当前网址是：" + location.href);
// 修改 href 就可以让浏览器发生跳转！
