}

// 假设HTML中有: 
// <h1 id="title">标题</h1>
// <div class="box">内容1</div>
// <div class="box">内容2</div>

// 1. 根据 ID 获取元素 (返回单个元素，最快)
const h1Ele = document.getElementById("title");

// 2. 根据 类名 获取元素 (返回一个集合/类数组)
const boxes = document.getElementsByClassName("box");
console.log(boxes[0]); // 获取第一个带box类的元素

// 3. 现代写法：querySelector (极力推荐！)
// 使用 CSS 选择器语法获取元素，只返回匹配的第一个元素
const firstBox = document.querySelector(".box");
const titleEle = document.querySelector("#title");

// querySelectorAll 返回所有匹配元素的集合(NodeList)
const allBoxes = document.querySelectorAll(".box");
allBoxes.forEach(box => {
  console.log(box);
});

const box = document.querySelector("#myBox");
const img = document.querySelector("#myImg");

// 1. 修改内部文本
// textContent 只会把内容当作纯文本，即使写了HTML标签也会被当成普通字符显示出来
box.textContent = "这是新的文本内容";

// 2. 修改内部HTML结构
// innerHTML 会解析字符串中的HTML标签！极其强大，但要注意防范 XSS 攻击。
box.innerHTML = "<strong>加粗的</strong>新内容";

// 3. 修改元素的标准属性 (src, href, id, className等)
img.src = "new-image.jpg";
img.alt = "这是一张新图片";

// 修改 class 属性 (注意JS中保留字问题，使用 className 或 classList)
box.className = "active highlight"; // 直接覆盖所有class

// 现代的 classList 操作（推荐）
box.classList.add("fade-in");    // 增加一个类
box.classList.remove("hidden");  // 移除一个类
box.classList.toggle("active");  // 切换（有就删，没有就加）

const btn = document.querySelector("#myBtn");

// 操作元素的 style 属性，相当于直接在HTML里写内联样式 (style="...")
// 注意：CSS中的带有连字符的属性名 (如 background-color)，
// 在JS中必须改成驼峰命名法 (backgroundColor)

btn.style.color = "white";
btn.style.backgroundColor = "#3178c6";
btn.style.fontSize = "18px";
btn.style.marginTop = "20px";
btn.style.display = "none"; // 隐藏元素

const list = document.querySelector("#myList"); // <ul id="myList">

// --- 创建与插入节点 ---
// 1. 在内存中创建一个空的 <li> 标签
const newLi = document.createElement("li");

// 2. 给它填充内容和样式
newLi.textContent = "我是新来的项目";
newLi.classList.add("list-item");

// 3. 把它插入到DOM树中 (追加到 ul 的末尾)
list.appendChild(newLi);


// --- 删除节点 ---
// 假设要删除刚才创建的节点
// 现代浏览器支持直接调用元素的 remove() 方法
newLi.remove();

// 传统的删除方法：必须让父节点来删除它的子节点
// list.removeChild(newLi);

const btn = document.querySelector("#loginBtn");
const input = document.querySelector("#username");

// 语法：元素.addEventListener("事件名", 事件处理函数)
btn.addEventListener("click", function() {
  // 当按钮被点击时，大括号里的代码才会执行
  let uname = input.value; // 获取输入框中的值

  if(uname === "") {
    alert("用户名不能为空！");
  } else {
    alert("欢迎你，" + uname);
  }
});

// 监听键盘事件 (按回车键登录)
input.addEventListener("keydown", function(event) {
  // event 对象包含了此次事件的所有详细信息
  // event.key 可以获取当前按下的具体按键名称
  if (event.key === "Enter") {
    // 触发按钮的点击事件
    btn.click();
  }
});

