import React, { useState } from 'react';

// 定义一个 React 组件 (本质上就是一个返回 JSX 的 JS 函数)
function App() {
  // 使用 useState 钩子来定义状态
  // count 是数据，setCount 是修改该数据的方法，初始值为 0
  const [count, setCount] = useState(0);

  return (
    // 下面看起来像 HTML，其实是 JSX 语法！它会被编译成 JS 对象
    <div className="app-container">
      <h1>你点击了 {count} 次</h1>

      {/* 绑定 onClick 事件，点击时调用 setCount 修改状态 */}
      <button onClick={() => setCount(count + 1)}>
        点我加1
      </button>
    </div>
  );
}

export default App;
